function rawNumber(value: number): SQL {
	return sql.raw(String(value));
}

function assertNonNegativeInteger(fnName: string, value: number): void {
	if (!Number.isInteger(value) || value < 0) {
		throw new DrizzleError({ message: `${fnName}() expects a non-negative integer argument, received: ${value}` });
	}
}

function assertPositiveInteger(fnName: string, value: number): void {
	if (!Number.isInteger(value) || value <= 0) {
		throw new DrizzleError({ message: `${fnName}() expects a positive integer argument, received: ${value}` });
	}
}

/**
 * Validates a name used to reference or declare a named window.
 */
export function assertValidWindowName(name: string): void {
	if (name.length === 0) {
		throw new DrizzleError({ message: 'Window name must be a non-empty string' });
	}
	if (name.trim().length === 0) {
		throw new DrizzleError({ message: 'Window name must not consist solely of whitespace' });
	}
}

/**
 * A boundary of a window frame (e.g. `unbounded preceding`, `5 preceding`, `current row`).
 */
export class WindowFrameBoundary implements SQLWrapper {
	static readonly [entityKind]: string = 'WindowFrameBoundary';

	constructor(private readonly sqlChunk: SQL, readonly rank: number) {}

	getSQL(): SQL {
		return this.sqlChunk;
	}
}

export const unboundedPreceding: WindowFrameBoundary = new WindowFrameBoundary(
	sql`unbounded preceding`,
	Number.NEGATIVE_INFINITY,
);

export const currentRow: WindowFrameBoundary = new WindowFrameBoundary(sql`current row`, 0);

export const unboundedFollowing: WindowFrameBoundary = new WindowFrameBoundary(
	sql`unbounded following`,
	Number.POSITIVE_INFINITY,
);

export function preceding(offset: number): WindowFrameBoundary {
	assertNonNegativeInteger('preceding', offset);
	return new WindowFrameBoundary(sql`${rawNumber(offset)} preceding`, -offset);
}

export function following(offset: number): WindowFrameBoundary {
	assertNonNegativeInteger('following', offset);
	return new WindowFrameBoundary(sql`${rawNumber(offset)} following`, offset);
}

export interface WindowFrameBounds {
	from: WindowFrameBoundary;
	to: WindowFrameBoundary;
}

function buildFrame(unit: 'rows' | 'range', bounds: WindowFrameBounds): SQL {
	if (bounds.from.rank > bounds.to.rank) {
		throw new DrizzleError({
			message: `${unit}(): the "from" boundary must not be ordered after the "to" boundary`,
		});
	}
	return sql`${sql.raw(unit)} between ${bounds.from} and ${bounds.to}`;
}

export function rows(bounds: WindowFrameBounds): SQL {
	return buildFrame('rows', bounds);
}

export function range(bounds: WindowFrameBounds): SQL {
	return buildFrame('range', bounds);
}

/**
 * Inline window specification, used either by `.over()` on a window function or by `.window()` on a select builder.
